NodeLibrary.push({
    nodetype: 'filter/mozzi_svf',
    help: {
    "summary": "High-quality State Variable Filter (SVF).",
    "inlets": {
        "in": "Audio signal input.",
        "cutoff": "Centre Frequency (20 - 4096 Hz).",
        "res": "Resonance (0-255). 0 = Maximum Resonance, 255 = No Resonance."
    },
    "outlets": {
        "out": "Filtered audio signal."
    },
    "usage": "Standard filter for synthesis. NOTE: Resonance is inverted - 0 is the sharpest setting!"
},
    nodeclass: "MozziSVF",
    description: "Multi-mode Resonant Filter.",
    mozzi: { 
        rate: 'audio', 
        includes: ["#include <StateVariable.h>"], 
        defaults: { in: "0", cutoff: "1200", res: "200" }, 
        global: function(n,v){ 
            var mode = (n.data && n.data.mode) ? n.data.mode : "LOWPASS";
            return "StateVariable<" + mode + "> " + v + ";"; 
        }, 
        control: function(n,v,i){ 
            return v+".setCentreFreq((int)"+i.cutoff+");\n\t"+v+".setResonance((uint8_t)"+i.res+");"; 
        },
        audio: function(n,v,i){ return v+"_out = "+v+".next((int)"+i.in+");"; } 
    },
    renderer: {
        'html': function(bodyElm, node) {
            if (!node.data) node.data = { mode: "LOWPASS" };
            var container = document.createElement('div');
            container.style.padding = "5px"; container.style.textAlign = "center";
            
            var select = document.createElement('select');
            select.className = "mozzi-buffer-select"; 
            ["LOWPASS", "BANDPASS", "HIGHPASS", "NOTCH"].forEach(function(m) {
                var opt = document.createElement('option');
                opt.value = m; opt.innerText = m;
                if (m === node.data.mode) opt.selected = true;
                select.appendChild(opt);
            });
            select.onchange = function() { node.data.mode = this.value; };
            container.appendChild(select);
            bodyElm.appendChild(container);
        }
    },
    rpdnode: {
    "title": "SVF Filter",
    "inlets": {
        "in": {
            "type": "mozziflow/string",
            "no_text": true,
            "color": "bipolar_8"
        },
        "cutoff": {
            "type": "mozziflow/string",
            "label": "Freq (20-4k)",
            "is_control": true,
            "color": "unipolar_16"
        },
        "res": {
            "type": "mozziflow/string",
            "label": "Res (Inv 0-255)",
            "is_control": true,
            "color": "unipolar_8"
        }
    },
    "outlets": {
        "out": {
            "type": "mozziflow/string",
            "color": "bipolar_8"
        }
    }
}
});

