NodeLibrary.push({
    nodetype: 'filter/mozzi_delay_fb',
    help: {
    "summary": "Professional Digital Delay with Feedback and variable buffer size.",
    "inlets": {
        "in": "Audio input signal.",
        "samples": "Delay time in samples. (At 16384Hz, 1638 samples = 100ms).",
        "feedback": "Repetition intensity (0-255, mapped to -128/127)."
    },
    "outlets": {
        "out": "Delayed signal with repetitions."
    },
    "usage": "Use dropdowns to set buffer size, interpolation (LINEAR for sweeps, ALLPASS for reverb) and data type (int8 saves 50% RAM). Warning: Buffer size must be a power of 2."
},
    nodeclass: "MozziDelayFB",
    description: "Configurable Delay with Feedback.",
    mozzi: {
        rate: "audio",
        includes: ["#include <mozzi_fixmath.h>","#include <AudioDelayFeedback.h>"],
        defaults: {"in":"0","samples":"512","feedback":"128"},
        global: function(n, v) { 
            var size = (n.data && n.data.bufferSize) ? n.data.bufferSize : 512;
            var interp = (n.data && n.data.interp) ? n.data.interp : "LINEAR";
            var type = (n.data && n.data.type) ? n.data.type : "int";
            return "AudioDelayFeedback<" + size + ", " + interp + ", " + type + "> " + v + ";"; 
        },
        control: function(n, v, i) { 
            return v + ".setFeedbackLevel((int8_t)((int)" + i.feedback + " - 128));\n\t" +
                   v + ".setDelayTimeCells((uint16_t)" + i.samples + ");";
        },
        audio: function(n, v, i) { 
            return v + "_out = " + v + ".next((int)" + i.in + ");"; 
        },
        inlet_rates: {"in":"audio","samples":"control","feedback":"control"},
    },
    renderer: {
        'html': function(bodyElm, node) {
            if (!node.data) node.data = { bufferSize: 512, interp: "LINEAR", type: "int" };
            var container = document.createElement('div');
            container.style.padding = "5px"; container.style.textAlign = "center";
            
            var addSelect = function(labelTxt, key, options) {
                var l = document.createElement('div');
                l.innerText = labelTxt; l.style.fontSize = "8px"; l.style.color = "#888";
                var s = document.createElement('select');
                s.className = "mozzi-buffer-select"; s.style.width = "100%";
                options.forEach(function(o) {
                    var opt = document.createElement('option');
                    opt.value = o; opt.innerText = o;
                    if (o == node.data[key]) opt.selected = true;
                    s.appendChild(opt);
                });
                s.onchange = function() { node.data[key] = this.value; };
                container.appendChild(l); container.appendChild(s);
            };

            addSelect("Buffer Size:", "bufferSize", [128, 256, 512, 1024, 2048, 4096]);
            addSelect("Interp:", "interp", ["LINEAR", "ALLPASS"]);
            addSelect("Type:", "type", ["int", "int8_t"]);
            
            bodyElm.appendChild(container);
        }
    },
    rpdnode: {
    "title": "Delay FB",
    "inlets": {
        "in": {
            "type": "mozziflow/string",
            "no_text": true,
            "color": "bipolar_8"
        },
        "samples": {
            "type": "mozziflow/string",
            "is_control": true,
            "color": "unipolar_16" // Delay time in samples
        },
        "feedback": {
            "type": "mozziflow/string",
            "is_control": true,
            "color": "unipolar_8"
        }
    },
    "outlets": {
        "out": {
            "type": "mozziflow/string",
            "color": "bipolar_8"
        }
    }
}
});

